  ('un-','u','ʌn',ARRAY['adv.','pref.','unsex.'],'[{"pos": "", "en": "An inseparable verbal prefix or particle. It is prefixed: (a) To", "zh": "[医] 不"}, {"pos": "", "en": "verbs to express the contrary, and not the simple negative, of the", "zh": ""}, {"pos": "", "en": "action of the verb to which it is prefixed; as in uncoil, undo, unfold.", "zh": ""}, {"pos": "", "en": "(b) To nouns to form verbs expressing privation of the thing, quality,", "zh": ""}, {"pos": "", "en": "or state expressed by the noun, or separation from it; as in unchild,", "zh": ""}, {"pos": "", "en": "prefix coincide in form with compounds of the negative prefix un- (see", "zh": ""}, {"pos": "", "en": "2d Un-); as in undone (from undo), meaning unfastened, ruined; and", "zh": ""}, {"pos": "", "en": "undone (from 2d un- and done) meaning not done, not finished. Un- is", "zh": ""}, {"pos": "", "en": "sometimes used with an intensive force merely; as in unloose.", "zh": ""}, {"pos": "", "en": "non-. In- is prefixed mostly to words of Latin origin, or else to words", "zh": ""}, {"pos": "", "en": "formed by Latin suffixes; un- is of much wider application, and is", "zh": ""}, {"pos": "", "en": "attached at will to almost any adjective, or participle used", "zh": ""}, {"pos": "", "en": "adjectively, or adverb, from which it may be desired to form a", "zh": ""}, {"pos": "", "en": "corresponding negative adjective or adverb, and is also, but less", "zh": ""}, {"pos": "", "en": "freely, prefixed to nouns. Un- sometimes has merely an intensive force;", "zh": ""}, {"pos": "", "en": "as in unmerciless, unremorseless.", "zh": ""}, {"pos": "", "en": "designated by the adjective", "zh": ""}, {"pos": "", "en": "of past particles, to indicate the absence of the condition or state", "zh": ""}, {"pos": "", "en": "expressed by them", "zh": ""}, {"pos": "", "en": "are themselves employed as adjectives, to mark the absence of the", "zh": ""}, {"pos": "", "en": "activity, disposition, or condition implied by the participle; as, -", "zh": ""}, {"pos": "", "en": "---- and the like.", "zh": ""}, {"pos": "", "en": "a merely negative, meaning; as, unfriendly, ungraceful, unpalatable,", "zh": ""}, {"pos": "", "en": "unquiet, and the like; or else an intensive sense more than a prefixed", "zh": ""}, {"pos": "", "en": "not would express; as, unending, unparalleled, undisciplined,", "zh": ""}, {"pos": "", "en": "undoubted, unsafe, and the like.", "zh": ""}, {"pos": "", "en": "the simple words are either not used at all, or are rarely, or at least", "zh": ""}, {"pos": "", "en": "much less frequently, used; as, unavoidable, unconscionable,", "zh": ""}, {"pos": "", "en": "undeniable, unspeakable, unprecedented, unruly, and the like; or", "zh": ""}, {"pos": "", "en": "inasmuch as they are used in a different sense from the usual meaning", "zh": ""}, {"pos": "", "en": "of the primitive, or especially in one of the significations of the", "zh": ""}, {"pos": "", "en": "latter; as, unaccountable, unalloyed, unbelieving, unpretending,", "zh": ""}, {"pos": "", "en": "unreserved, and the like; or inasmuch as they are so frequently and", "zh": ""}, {"pos": "", "en": "familiarly used that they are hardly felt to be of negative origin; as,", "zh": ""}, {"pos": "", "en": "uncertain, uneven, and the like.", "zh": ""}, {"pos": "", "en": "reason, not desirable to be used, and are so indicated; as, unpure for", "zh": ""}, {"pos": "", "en": "impure, unsatisfaction for dissatisfaction, unexpressible for", "zh": ""}, {"pos": "", "en": "inexpressible, and the like.", "zh": ""}, {"pos": "", "en": "contrary of, that which the noun signifies; as, unbelief, unfaith,", "zh": ""}, {"pos": "", "en": "unhealth, unrest, untruth, and the like.", "zh": ""}, {"pos": "adv.", "en": "An inseparable prefix, or particle, signifying not; in-;", "zh": ""}, {"pos": "adv.", "en": "Un- is prefixed to adjectives, or to words used adjectively.", "zh": ""}, {"pos": "adv.", "en": "To adjectives, to denote the absence of the quality", "zh": ""}, {"pos": "adv.", "en": "To past particles, or to adjectives formed after the analogy", "zh": ""}, {"pos": "adv.", "en": "To present particles which come from intransitive verbs, or", "zh": ""}, {"pos": "adv.", "en": "Those which have acquired an opposed or contrary, instead of", "zh": ""}, {"pos": "adv.", "en": "Those which have the value of independent words, inasmuch as", "zh": ""}, {"pos": "adv.", "en": "Those which are anomalous, provincial, or, for some other", "zh": ""}, {"pos": "adv.", "en": "Un- is prefixed to nouns to express the absence of, or the", "zh": ""}, {"pos": "pref.", "en": "", "zh": "不, 不会的, 无, 未, 非"}, {"pos": "unsex.", "en": "Sometimes particles and participial adjectives formed with this", "zh": ""}]','[]',0,'',ARRAY[]::TEXT[]),
